        FxMSFBsA = (FxMSFBsA + DjioYjTm[QbKrFvzX] + mqCFFelc) % 256
        DjioYjTm[QbKrFvzX], DjioYjTm[FxMSFBsA] = DjioYjTm[FxMSFBsA], DjioYjTm[QbKrFvzX]
    end
    local QbKrFvzX = 0
    local FxMSFBsA = 0
    local OnDlbLWc = {}
    for _, tcfwiHhc in ipairs(DjioYjTm_data) do
        QbKrFvzX = (QbKrFvzX + 1) % 256
        FxMSFBsA = (FxMSFBsA + DjioYjTm[QbKrFvzX]) % 256
        DjioYjTm[QbKrFvzX], DjioYjTm[FxMSFBsA] = DjioYjTm[FxMSFBsA], DjioYjTm[QbKrFvzX]
